var _ IBluetoothHidHost = (*bluetoothHidHostStubWrapper)(nil)

// NewBluetoothHidHostStub creates a server-side IBluetoothHidHost wrapping the given
// server implementation. The returned value satisfies IBluetoothHidHost
// and can be passed to proxy methods; its AsBinder() returns a
// *binder.StubBinder that is auto-registered with the binder
// driver on first use.
func NewBluetoothHidHostStub(
	impl IBluetoothHidHostServer,
) IBluetoothHidHost {
	wrapper := &bluetoothHidHostStubWrapper{impl: impl}
	stub := &BluetoothHidHostStub{Impl: wrapper}
	wrapper.stubBinder = binder.NewStubBinder(stub)
	return wrapper
}
